/**
 * @fileoverview HintBox component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, default config
 *   helpers.js   — escapeHTML, highlightMatch
 *   view.js      — DOM setup / teardown, rendering, positioning
 *   events.js    — centralised event binding (input, keydown, focus, outside click)
 *
 * @module module/HintBox
 */

import { default as razyui, Elements } from '../../index.js';
import { zIndexRegistry } from '../shared/ZIndexRegistry.js';
import { StateMachine } from '../shared/StateMachine.js';
import { HintBoxDef as DEF } from '../HintBox.def.js';

import { DEFAULTS }                                        from './constants.js';
import { createDropdown, renderList, positionDropdown,
         setActiveItem, cleanupDOM }                       from './view.js';
import { createHandlerCtx, bindEvents }                    from './events.js';
import { emitEvent }                                       from '../shared/emitEvent.js';

/**
 * HintBox — Autocomplete / Hint dropdown for RazyUI v2 (JIT-compatible)
 *
 * Attaches a floating suggestion list to an input element.
 * Supports static data, async functions, and AJAX endpoints.
 *
 * Refactored to use:
 *   - ComponentDefinition (HintBox.def.js) for tokens & state machine
 *   - StateMachine for dropdown open/closed state management
 *   - Design tokens via --hb-* CSS custom properties (no magic numbers)
 *   - Custom Element registration via razyui.ce()
 *
 * Config:
 *   source      — string (AJAX URL) | Array | function(query) → Array|Promise<Array>
 *   minLength   — min chars before triggering (default 1)
 *   delay       — debounce ms (default 300)
 *   maxItems    — max visible items (default 10)
 *   labelKey    — object key for display text (default 'label')
 *   valueKey    — object key for value (default 'value')
 *   queryParam  — URL param name for AJAX (default 'q')
 *   method      — HTTP method for AJAX (default 'GET')
 *   highlight   — highlight matching text (default true)
 *   placeholder — placeholder text for empty state
 *   itemTemplate — function(item, query) → HTML string
 *   onSelect    — function(item, inputEl)
 *   onOpen      — function()
 *   onClose     — function()
 *
 * getControl() API:
 *   .open()      — manually open dropdown
 *   .close()     — close dropdown
 *   .destroy()   — cleanup
 *   .element     — the input element
 */

const HintBox = class {

    #el         = null;   // raw input element
    #container  = null;   // Elements wrapper of input
    #dropdown   = null;   // floating list element
    #config     = {};
    #items      = [];
    #activeIdx  = -1;
    #timer      = 0;
    #sm         = null;   // StateMachine for open/closed state
    #destroyed  = false;
    #query      = '';
    #justSelected = false;
    #eventCleanup = null;

    constructor(selector, config = {}) {
        let el = razyui.isStr(selector)
            ? razyui(selector)[0]
            : selector;
        if (!el) { console.warn('HintBox: element not found \u2192', selector); return; }

        // If the target isn't an <input>, find the input inside (e.g. custom element wrapper)
        if (el.tagName !== 'INPUT') {
            el = el.querySelector('input') || el;
        }

        this.#el = el;
        this.#container = new Elements(el);
        this.#config = { ...DEFAULTS, ...config };

        this.#init();
    }

    #init() {
        const el = this.#container;

        // Ensure autocomplete is off
        el.attr('autocomplete', 'off');

        // Create dropdown
        this.#dropdown = createDropdown();

        // Create StateMachine for dropdown open/closed
        this.#sm = new StateMachine(DEF.states, {
            dropdown: this.#dropdown[0],
        });

        // Bind SM open/close effects to callbacks
        this.#sm.onChange((next) => {
            if (next === 'open') {
                emitEvent(this.#el, 'open');
                if (razyui.isFn(this.#config.onOpen))  this.#config.onOpen();
            }
            if (next === 'closed') {
                emitEvent(this.#el, 'close');
                if (razyui.isFn(this.#config.onClose)) this.#config.onClose();
            }
        });

        // Build handler context and bind events
        const self = this;
        const handlerCtx = createHandlerCtx(() => ({
            get justSelected()      { return self.#justSelected; },
            set justSelected(v)     { self.#justSelected = v; },
            isOpen:      self.#sm.is('open'),
            itemCount:   self.#items.length,
            activeIdx:   self.#activeIdx,
            inputValue:  (self.#el.value ?? '').trim(),
            minLength:   self.#config.minLength,
            onInput:     () => self.#onInput(),
            setActive:   (idx) => self.#setActive(idx),
            select:      (idx) => self.#select(idx),
            close:       () => self.#close(),
        }));

        this.#eventCleanup = bindEvents(
            el, this.#el, this.#dropdown[0], handlerCtx
        );
    }

    #onInput() {
        const query = this.#el.value.trim();
        this.#query = query;

        if (this.#timer) clearTimeout(this.#timer);

        if (query.length < this.#config.minLength) {
            this.#close();
            return;
        }

        this.#timer = setTimeout(() => {
            this.#fetch(query);
        }, this.#config.delay);
    }

    async #fetch(query) {
        const cfg = this.#config;
        let items;

        if (razyui.isStr(cfg.source)) {
            // AJAX endpoint
            try {
                const sep = cfg.source.includes('?') ? '&' : '?';
                const url = `${cfg.source}${sep}${encodeURIComponent(cfg.queryParam)}=${encodeURIComponent(query)}`;
                const response = await fetch(url, { method: cfg.method });
                items = await response.json();
            } catch {
                items = [];
            }
        } else if (razyui.isFn(cfg.source)) {
            const result = cfg.source(query);
            items = result instanceof Promise ? await result : result;
        } else if (Array.isArray(cfg.source)) {
            const lower = query.toLowerCase();
            items = cfg.source.filter(item => {
                const text = razyui.isPO(item) ? String(item[cfg.labelKey] || '') : String(item);
                return text.toLowerCase().includes(lower);
            });
        } else {
            items = [];
        }

        if (!Array.isArray(items)) items = [];

        // Respect maxItems
        this.#items = items.slice(0, cfg.maxItems);
        this.#activeIdx = -1;

        if (this.#items.length > 0) {
            this.#renderList();
            this.#show();
        } else {
            this.#close();
        }
    }

    #renderList() {
        renderList(this.#dropdown, this.#items, this.#config, this.#query, {
            onSelect:   (idx) => this.#select(idx),
            onActivate: (idx) => this.#setActive(idx),
        });
    }

    #show() {
        if (this.#sm.is('open')) { positionDropdown(this.#el, this.#dropdown); return; }
        this.#sm.send('OPEN');
        zIndexRegistry.acquire(this.#dropdown[0]);
        positionDropdown(this.#el, this.#dropdown);
    }

    #close() {
        if (!this.#sm.is('open')) return;
        this.#activeIdx = -1;
        zIndexRegistry.release(this.#dropdown[0]);
        this.#sm.send('CLOSE');
    }

    #setActive(idx) {
        setActiveItem(this.#dropdown, idx);
        this.#activeIdx = idx;
    }

    #select(idx) {
        const item = this.#items[idx];
        if (!item) return;

        const cfg = this.#config;

        // onItemClick — return false to prevent default select behaviour
        if (razyui.isFn(cfg.onItemClick)) {
            if (cfg.onItemClick(item, this.#el) === false) return;
        }

        const value = razyui.isPO(item) ? String(item[cfg.valueKey] ?? item[cfg.labelKey] ?? '') : String(item);

        this.#justSelected = true;
        this.#el.value = value;
        this.#el.dispatchEvent(new Event('input', { bubbles: true }));
        this.#close();
        this.#el.blur();

        emitEvent(this.#el, 'select', { item, value });
        if (razyui.isFn(cfg.onSelect)) {
            cfg.onSelect(item, this.#el);
        }
    }

    // ── Public API ──

    open()  { this.#show(); }
    close() { this.#close(); }
    toggle() { this.#sm.is('open') ? this.#close() : this.#show(); }
    get isOpen() { return this.#sm.is('open'); }

    getControl() {
        const self = this;
        return {
            get element() { return self.#el; },
            open:      () => self.open(),
            close:     () => self.close(),
            toggle:    () => self.toggle(),
            get isOpen() { return self.isOpen; },
            setSource: (source) => { self.#config.source = source; },
            destroy:   () => self.destroy(),
            get destroyed() { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        if (this.#timer) clearTimeout(this.#timer);
        this.#close();
        if (this.#eventCleanup) this.#eventCleanup();
        cleanupDOM(this.#dropdown);
    }
};

export default HintBox;
