/**
 * @fileoverview HintBox helpers — pure utility functions.
 * @module module/HintBox/helpers
 */

import razyui from '../../index.js';

/** Shared element for HTML-entity escaping (SSR-safe). */
const _escDiv = typeof document !== 'undefined' ? razyui.el('div') : null;

/**
 * Escape a plain-text string for safe insertion into innerHTML.
 *
 * @param {string} str
 * @returns {string} HTML-escaped string
 */
export function escapeHTML(str) {
    if (!_escDiv) return str;
    return _escDiv.text(str).html();
}

/**
 * Return HTML with regex-matched substrings wrapped in `<mark>` tags.
 *
 * @param {string} text    — raw display text
 * @param {string} keyword — search term to highlight
 * @param {string} [cls]   — optional CSS class for the <mark>
 * @returns {string} HTML string with highlights
 */
export function highlightMatch(text, keyword, cls) {
    if (!keyword) return escapeHTML(text);
    const escaped = keyword.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const re = new RegExp('(' + escaped + ')', 'gi');
    const tag = cls ? `<mark class="${cls}">` : '<mark>';
    return escapeHTML(text).replace(re, tag + '$1</mark>');
}
